1	//! `web-clean` — a clean-room reimplementation of the response bodies produced
2	//! by the tamarin-prover interactive web UI.
3	//!
4	//! This crate reproduces the *web layer's* output: the URL route grammar, the
5	//! JSON response envelopes, and the HTML/DOT/text page templates. Content that
6	//! the prover produces (pretty-printed terms, constraint systems, proof-method
7	//! names, graph bodies) is treated as opaque input supplied by the caller — the
8	//! crate reproduces the scaffolding, escaping, links and envelopes around it.
9	//!
10	//! Everything here was derived from black-box observation of captured responses
11	//! and live probing; see `workspace/BEHAVIOR.md` for the observed spec.
12	//!
13	//! Module map:
14	//! * [`route`] — parse a request path into a structured route (the grammar).
15	//! * [`envelope`] — the two JSON response shapes (`{html,title}`, `{redirect}`).
16	//! * [`escape`] — HTML entity escaping.
17	//! * [`page`] — the full theory-view HTML shell (the `overview/*` pages).
18	//! * [`proofscript`] — the proof-script (west) pane and proof-tree line grammar.
19	//! * [`forms`] — the edit / delete / add-lemma form bodies.
20	//! * [`intdot`] — the `intdot` mini-page and empty-graph DOT skeleton.
21	//! * [`text`] — the plain-text bodies (`source`/`message`, `next`/`prev`).
22	//! * [`errors`] — the 404 Not Found page.
23	
24	pub mod envelope;
25	pub mod errors;
26	pub mod escape;
27	pub mod forms;
28	pub mod intdot;
29	pub mod page;
30	pub mod proofscript;
31	pub mod route;
32	pub mod text;
33	
34	mod notfound_template;
35	mod shell_template;
36

1	//! JSON response envelopes for the `main/*` (and `method/*`, `autoprove/*`)
2	//! AJAX handlers.
3	//!
4	//! Observed: every `kind=json` response body is one of exactly two compact
5	//! JSON objects, with keys in this order and no insignificant whitespace:
6	//!   * content:  `{"html":<string>,"title":<string>}`
7	//!   * redirect: `{"redirect":<string>}`
8	//!
9	//! There is no trailing newline. Non-ASCII is emitted as literal UTF-8 (no
10	//! `\uXXXX`), and `/ < > &` are NOT backslash/entity escaped inside the JSON
11	//! string — i.e. standard JSON string escaping (only `" \` and control chars).
12	//! `serde_json`'s default serialization reproduces this exactly.
13	
14	use serde::Serialize;
15	
16	/// A content pane response: rendered HTML plus the pane title.
17	#[derive(Serialize)]
18	pub struct Content<'a> {
19	    pub html: &'a str,
20	    pub title: &'a str,
21	}
22	
23	/// A redirect response instructing the client to navigate to `redirect`.
24	#[derive(Serialize)]
25	pub struct Redirect<'a> {
26	    pub redirect: &'a str,
27	}
28	
29	/// Serialize `{"html":..,"title":..}` exactly as the web layer does.
30	pub fn render_content(html: &str, title: &str) -> String {
31	    serde_json::to_string(&Content { html, title }).expect("Content serializes")
32	}
33	
34	/// Serialize `{"redirect":..}` exactly as the web layer does.
35	pub fn render_redirect(path: &str) -> String {
36	    serde_json::to_string(&Redirect { redirect: path }).expect("Redirect serializes")
37	}
38	
39	#[cfg(test)]
40	mod tests {
41	    use super::*;
42	
43	    #[test]
44	    fn content_envelope_shape() {
45	        assert_eq!(
46	            render_content("this is a mistake<br/>\n", "Lemma: exec"),
47	            r#"{"html":"this is a mistake<br/>\n","title":"Lemma: exec"}"#
48	        );
49	    }
50	
51	    #[test]
52	    fn redirect_envelope_shape() {
53	        assert_eq!(
54	            render_redirect("/thy/trace/4/overview/proof/exec/_"),
55	            r#"{"redirect":"/thy/trace/4/overview/proof/exec/_"}"#
56	        );
57	    }
58	
59	    #[test]
60	    fn keeps_literal_utf8_and_unescaped_angle_brackets() {
61	        let s = render_content("<span>∃</span>", "t");
62	        assert!(s.contains("<span>∃</span>"), "got {s}");
63	        assert!(!s.contains("\\u"), "should not \\u-escape: {s}");
64	    }
65	}
